/**
 * @fileoverview Spinner component — modular entry point.
 * @module module/Spinner
 */

import { default as razyui } from '../../index.js';
import { SpinnerDef as DEF } from '../Spinner.def.js';
import { DEFAULTS } from './constants.js';
import { setupDOM, cleanupDOM } from './view.js';

const Spinner = class {
    #root = null;

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Spinner: element not found →', selector); return; }
        this.#root = root;
        setupDOM(root, { ...DEFAULTS, ...config });
    }

    destroy() { cleanupDOM(this.#root); }
};

export default Spinner;
