/**
 * @fileoverview Spinner barrel.
 * @module module/Spinner
 */
import { default as razyui } from '../index.js';
import { SpinnerDef as DEF } from './Spinner.def.js';
import Spinner from './Spinner/index.js';

razyui.Spinner = Spinner;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Spinner);
}

export default Spinner;

export const stylesheet = null;
