/**
 * @fileoverview Spinner view — DOM setup.
 * @module module/Spinner/view
 */

import { CLS, PART } from './constants.js';

export function setupDOM(root, config) {
    const { size, label } = config;

    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    if (size === 'sm') {
        PART.SM_ROOT.apply(root);
    } else if (size === 'lg') {
        PART.LG_ROOT.apply(root);
    }

    const el = root[0];
    el.setAttribute('role', 'status');
    el.setAttribute('aria-label', label || 'Loading');

    // Ring
    const $ring = PART.RING.create();
    root.append($ring);

    // Label
    let labelEl = null;
    if (label) {
        labelEl = PART.LABEL.create();
        labelEl.text(label);
        root.append(labelEl);
    }

    return { ringEl: $ring, labelEl };
}

export function cleanupDOM(root) {
    root.removeClass(CLS.ROOT);
    root[0].innerHTML = '';
}
